import { promises as fs } from "node:fs";
import { execFileSync } from "node:child_process";
import { tmpdir } from "node:os";
import { join, resolve } from "node:path";
import { runBioQueryFromManifest, runBioOperationFromManifest } from "../dist/hosts/run-store.js";
import { nodeComputeRunner } from "../dist/process/node-compute-runner.js";
import { fsCasStore } from "../dist/hosts/fs-cas.js";

// LITERATE PROGRAMMING (the R/knitr discipline), generalized: every runnable example README's recorded-run
// block is GENERATED by the AGENT RUNNING the manifest through the substrate — not hand-pasted prose that
// drifts. The substrate's run IS the literate artifact (result.json + receipts.json); each block below is just
// formatting a real run. `--check` fails if a committed block is stale; an example whose dependency is absent
// (R/nanoarrow for the out-of-process examples) SKIPS, so `npm run check` stays green on machines without R.
//
//   npm run readme:examples           # regenerate every block
//   npm run readme:examples -- --check
//
// One config-driven generator over a table of examples. Each entry names its manifest, its dependency (so it
// can skip), its probe(s) (a declared operation or ad-hoc SQL run through the host), and a `render` that turns
// the probe rows into the markdown block body. ONLY deterministic, no-external-network examples live here.

const check = process.argv.includes("--check");

// R `nanoarrow` (the Arrow-IPC codec) gates the out-of-process COMPUTE examples; absent => they skip.
const rNanoarrow = (() => {
  try { execFileSync("Rscript", ["-e", 'if(!requireNamespace("nanoarrow",quietly=TRUE)) quit(status=1)'], { stdio: "ignore" }); return true; } catch { return false; }
})();
const DEPS = { none: { ok: true, why: "" }, "r-nanoarrow": { ok: rNanoarrow, why: "R 'nanoarrow' not available" } };
const NANOARROW_INIT = ["INSTALL nanoarrow FROM community", "LOAD nanoarrow"];

// Run one probe (a declared operation OR ad-hoc SQL) through the host and return its result.json rows.
async function runProbe(ex, probe) {
  const cwd = await fs.mkdtemp(join(tmpdir(), "ex-gen-"));
  const common = {
    cwd, dbPath: ":memory:", manifestPath: ex.manifest,
    runId: "g" + Math.random().toString(36).slice(2), now: "T1",
    ...(ex.compute ? { compute: { runner: nodeComputeRunner() } } : {}),
    ...(ex.cas ? { cas: fsCasStore(await fs.mkdtemp(join(tmpdir(), "ex-cas-"))) } : {}), // for examples that declare file outputs
    ...(ex.duckdbInitSql ? { duckdbInitSql: ex.duckdbInitSql } : {}),
  };
  const o = probe.operationId
    ? await runBioOperationFromManifest({ ...common, operationId: probe.operationId })
    : await runBioQueryFromManifest({ ...common, sql: probe.sql });
  if (!o.ok) throw new Error(`${ex.id} probe failed: ${o.error}`);
  return JSON.parse(await fs.readFile(join(o.runDir, "result.json"), "utf8")).rows;
}

// Render a list of uniform row objects as a fixed-width text table (the columns in declared order).
function textTable(rows, cols) {
  const head = cols.map((c) => c.label ?? c.key);
  const cells = rows.map((r) => cols.map((c) => (c.fmt ? c.fmt(r[c.key]) : String(r[c.key]))));
  const w = head.map((h, i) => Math.max(h.length, ...cells.map((row) => row[i].length)));
  const line = (vals) => vals.map((v, i) => (cols[i].right ? v.padStart(w[i]) : v.padEnd(w[i]))).join("  ").trimEnd();
  return ["```", line(head), ...cells.map(line), "```"].join("\n");
}

const fix3 = (n) => Number(n).toFixed(3);

const EXAMPLES = [
  {
    id: "coloc-run",
    dir: "examples/coloc",
    deps: "r-nanoarrow",
    compute: true,
    duckdbInitSql: NANOARROW_INIT,
    probes: {
      harm: { sql: "SELECT tissue, count(*) n FROM harmonized GROUP BY tissue" },
      pp: {
        sql: `SELECT tissue,
            round(max(CASE WHEN hypothesis='PP.H1' THEN posterior END),3) AS H1,
            round(max(CASE WHEN hypothesis='PP.H3' THEN posterior END),3) AS H3,
            round(max(CASE WHEN hypothesis='PP.H4' THEN posterior END),3) AS H4
            FROM coloc_result GROUP BY tissue ORDER BY H4 DESC`,
      },
    },
    render({ harm, pp }) {
      const n = Object.fromEntries(harm.map((r) => [r.tissue, Number(r.n)]));
      const note = { Whole_Blood: "COLOCALIZED (shared causal rs6)", Liver: "same locus, DIFFERENT causal (eQTL peak rs3)", Brain: "GWAS signal only (no eQTL)" };
      const lines = pp.map((r) => `  ${String(r.tissue).padEnd(12)} ${fix3(r.H1)}   ${fix3(r.H3)}   ${fix3(r.H4)}   ${String(n[r.tissue] ?? "?").padStart(3)}    ← ${note[r.tissue] ?? ""}`.trimEnd());
      return [
        "*Generated by `npm run readme:examples` — the agent running the manifest through out-of-process R compute.*",
        "",
        "```",
        "  tissue       PP.H1   PP.H3   PP.H4   nSNPs",
        ...lines,
        "```",
        "",
        `The colocalizing tissue (top \`PP.H4\`) is **${pp[0]?.tissue}**.`,
      ].join("\n");
    },
  },
  {
    id: "lm-run",
    dir: "examples/compute-run",
    deps: "r-nanoarrow",
    compute: true,
    duckdbInitSql: NANOARROW_INIT,
    probes: { fit: { sql: "SELECT n, slope, intercept, r_squared FROM lm_fit" } },
    render({ fit }) {
      const r = fit[0];
      return [
        "*Generated by `npm run readme:examples` — the agent running the manifest (real spawned `Rscript`).*",
        "",
        textTable(fit, [
          { key: "n", label: "n", right: true },
          { key: "slope", label: "slope", right: true, fmt: (v) => Number(v).toFixed(4) },
          { key: "intercept", label: "intercept", right: true, fmt: (v) => Number(v).toFixed(4) },
          { key: "r_squared", label: "r_squared", right: true, fmt: (v) => Number(v).toFixed(5) },
        ]),
        "",
        `The points are ≈ \`y = 2x + 1\`; the out-of-process \`lm()\` recovers **slope ${Number(r.slope).toFixed(3)}**, **intercept ${Number(r.intercept).toFixed(3)}**, **R² ${Number(r.r_squared).toFixed(4)}** over ${Number(r.n)} rows.`,
      ].join("\n");
    },
  },
  {
    id: "artifacts-run",
    dir: "examples/compute-artifacts",
    deps: "r-nanoarrow",
    compute: true,
    cas: true, // declares file outputs -> needs a CAS store
    duckdbInitSql: NANOARROW_INIT,
    probes: { summary: { sql: "SELECT n, mean_x, status FROM summary" } },
    render({ summary }) {
      const r = summary[0];
      return [
        "*Generated by `npm run readme:examples` — the agent running the manifest (real spawned `Rscript`, CAS bound).*",
        "",
        textTable(summary, [
          { key: "n", label: "n", right: true },
          { key: "mean_x", label: "mean_x", right: true, fmt: (v) => Number(v).toFixed(1) },
          { key: "status", label: "status" },
        ]),
        "",
        `The VALUE came back as a table (n=${Number(r.n)}); the declared FILE outputs (\`rows.csv\`, \`report.txt\`, \`plot.svg\`) were captured into CAS — verified content-addressed in \`test/compute-artifacts-example.test.ts\`.`,
      ].join("\n");
    },
  },
  {
    id: "files-only-run",
    dir: "examples/compute-files-only",
    deps: "none", // a `sh` tool — no R, no nanoarrow (a files-only op loads no Arrow codec)
    compute: true,
    cas: true, // declares file outputs -> needs a CAS store
    probes: { tracks: { sql: "SELECT name, kind, size FROM tracks ORDER BY name" } },
    render({ tracks }) {
      return [
        "*Generated by `npm run readme:examples` — the agent running the files-only manifest (real spawned `sh`, CAS bound, no Arrow codec).*",
        "",
        textTable(tracks, [
          { key: "name", label: "name" },
          { key: "kind", label: "kind" },
          { key: "size", label: "size", right: true, fmt: (v) => String(Number(v)) },
        ]),
        "",
        `The tool returned NO rectangular value — the table IS the captured-artifacts listing (${tracks.length} files, each a content-addressed CAS handle). Verified in \`test/compute-files-only-example.test.ts\`.`,
      ].join("\n");
    },
  },
  {
    id: "rhi-run",
    dir: "examples/rare-high-impact",
    deps: "none",
    probes: { report: { operationId: "rare_high_impact.report" } },
    render({ report }) {
      const order = ["included", "no_frequency", "not_rare", "not_high_impact", "benign"];
      const note = {
        included: "rare LoF, frequency known — the defensible count",
        no_frequency: "ABSTAINED — unknown allele frequency (not counted as rare)",
        not_rare: "high-impact but common (AF ≥ 0.01)",
        not_high_impact: "rare, but not a loss-of-function consequence",
        benign: "rare LoF but clinically Benign — excluded (safety)",
      };
      const by = Object.fromEntries(report.map((r) => [r.bucket, Number(r.n)]));
      const lines = order.filter((b) => b in by).map((b) => `  ${b.padEnd(16)} ${String(by[b]).padStart(2)}    ← ${note[b]}`);
      return [
        "*Generated by `npm run readme:examples` — the agent running the declared `rare_high_impact.report` operation.*",
        "",
        "```",
        "  bucket            n",
        ...lines,
        "```",
        "",
        `The defensible answer is **included = ${by.included ?? 0}**: the unknown-frequency variant is **abstained** (not silently counted as rare), and the rare-but-Benign loss-of-function variant is **excluded**.`,
      ].join("\n");
    },
  },
  {
    id: "variants-run",
    dir: "examples/variant-counts",
    deps: "none",
    probes: { byConsequence: { sql: "SELECT consequence, CAST(count(*) AS INTEGER) AS n FROM variants GROUP BY consequence ORDER BY consequence" } },
    render({ byConsequence }) {
      return [
        "*Generated by `npm run readme:examples` — the agent's ad-hoc SQL over the declared `variants` table.*",
        "",
        textTable(byConsequence, [
          { key: "consequence", label: "consequence" },
          { key: "n", label: "n", right: true },
        ]),
        "",
        "No operation was declared — the manifest ships only the `variants` resource, and the agent wrote the `GROUP BY` after a schema probe.",
      ].join("\n");
    },
  },
];

let stale = 0;
for (const ex of EXAMPLES) {
  ex.manifest = resolve(ex.dir, "manifest.json");
  const readmePath = resolve(ex.dir, "README.md");
  const BEGIN = `<!-- BEGIN GENERATED:${ex.id} (npm run readme:examples — do not edit by hand) -->`;
  const END = `<!-- END GENERATED:${ex.id} -->`;
  const readme = await fs.readFile(readmePath, "utf8");
  const re = new RegExp(`${BEGIN.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}[\\s\\S]*?${END.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}`);
  if (!re.test(readme)) { console.error(`generate-example-readmes: markers for '${ex.id}' not found in ${readmePath}`); process.exit(1); }

  const dep = DEPS[ex.deps];
  if (!dep.ok) { console.log(`generate-example-readmes: ${ex.id} ${check ? "check " : ""}skipped — ${dep.why}`); continue; }

  const results = {};
  for (const [name, probe] of Object.entries(ex.probes)) results[name] = await runProbe(ex, probe);
  const fresh = [BEGIN, ex.render(results), END].join("\n");
  const updated = readme.replace(re, fresh);
  if (check) {
    if (updated !== readme) { console.error(`generate-example-readmes: '${ex.id}' block is STALE — run \`npm run readme:examples\``); stale++; }
    else console.log(`generate-example-readmes: ${ex.id} block is current`);
  } else {
    if (updated !== readme) await fs.writeFile(readmePath, updated);
    console.log(`generate-example-readmes: ${updated !== readme ? "regenerated" : "unchanged"} ${ex.id} block`);
  }
}
if (check && stale > 0) process.exit(1);
